import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.airtable.com/mcp",
  description: "Airtable: bases, tables, and records.",
  auth: connect({ connector: "airtable", principalType: "app" }),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.mem0.ai/mcp",
  description: "Mem0: store and retrieve persistent agent memory.",
  auth: connect({ connector: "mem0", principalType: "app" }),
});

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type LeadRecord = {
  leadId: string;
  fit: "strong" | "moderate" | "weak" | "disqualified";
  reasons: string[];
  company?: string;
  role?: string;
  scoredAt: string;
};

const STORE_PATH = path.join(process.cwd(), "var", "leads.json");

export async function saveLead(record: LeadRecord): Promise<LeadRecord> {
  let all: LeadRecord[] = [];
  try {
    all = JSON.parse(await readFile(STORE_PATH, "utf-8")) as LeadRecord[];
  } catch {
    all = [];
  }
  const next = all.filter((item) => item.leadId !== record.leadId);
  next.push(record);
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(next, null, 2)}\n`, "utf-8");
  return record;
}

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Hand a scored lead to sales by writing a context-rich brief. Approval-gated.",
  inputSchema: z.object({
    leadId: z.string().min(1),
    markdown: z.string().min(1),
  }),
  approval: always(),
  async execute({ leadId, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const handoffPath = `handoffs/${leadId}.md`;
    await sandbox.writeTextFile({ path: handoffPath, content: markdown });
    return { handedOff: true, path: handoffPath };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveLead } from "../lib/lead-store";

export default defineTool({
  description:
    "Score an inbound lead against the ICP and store the result for handoff.",
  inputSchema: z.object({
    leadId: z.string().min(1),
    fit: z.enum(["strong", "moderate", "weak", "disqualified"]),
    reasons: z.array(z.string().min(1)).min(1),
    company: z.string().optional(),
    role: z.string().optional(),
  }),
  async execute(input) {
    const record = await saveLead({
      ...input,
      scoredAt: new Date().toISOString(),
    });
    return { saved: true, record };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Handing a lead to sales parks on approval.",
  async test(t) {
    await t.send(
      "Hand lead-1 to sales now: markdown brief with ICP fit and next steps."
    );
    t.parked();
    t.calledTool("handoff_to_sales", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Scoring a lead persists fit and reasons.",
  async test(t) {
    await t.send(
      "Score lead lead-1 as strong fit. Company Acme, role Head of Eng. Reasons: 80 employees, shipping agents in prod."
    );
    t.succeeded();
    t.calledTool("score_lead", { input: { leadId: "lead-1", fit: "strong" } });
  },
});

